    fun dispose()

    suspend fun scanNeuroFocusDevices(): List<BleDeviceCandidate>

    /**
     * Connect to a device chosen from [scanNeuroFocusDevices].
     */
    suspend fun connectToDeviceAddress(address: String)
}
