                }
                fun finishEarlyEmpty() {
                    handler.removeCallbacks(finishRunnable)
                    if (!resumed.compareAndSet(false, true)) return
                    try {
                        scanner.stopScan(scanCallback)
                    } catch (_: Throwable) {
                    }
                    cont.resume(emptyList())
