                            }

                            override fun onScanResult(callbackType: Int, result: ScanResult) {
                                val name = result.device.name
                                    ?: result.scanRecord?.deviceName
                                    ?: return
                                if (name.startsWith(BleSpec.DEVICE_NAME_PREFIX)) {
