    private fun ingestSample(sample: Long) {
        synchronized(ringBufferLock) {
            lastSample = sample
            ring[ringWrite] = sample
            ringWrite = (ringWrite + 1) % RING_SIZE
            if (ringCount < RING_SIZE) ringCount++
            updateTick++
